func mustDecodeSnapshotData() []byte {
	zr, err := gzip.NewReader(base64.NewDecoder(base64.StdEncoding, strings.NewReader(snapshotDataB64)))
	if err != nil {
		panic(fmt.Errorf("wbgen: decode snapshot: %w", err))
	}
	data, err := io.ReadAll(zr)
	closeErr := zr.Close()
	if err != nil {
		panic(fmt.Errorf("wbgen: read snapshot: %w", err))
	}
	if closeErr != nil {
		panic(fmt.Errorf("wbgen: close snapshot: %w", closeErr))
	}
	if len(data) != snapshotDataLen {
		panic(fmt.Errorf("wbgen: snapshot length %d, want %d", len(data), snapshotDataLen))
	}
	return data
}

var snapshotData = mustDecodeSnapshotData()

